## Example 1: 4-Bit Adder

### Behavioral Model

```verilog
// Behavioral: Describes the ADDITION operation
module adder_behavioral (
    input [3:0] a,
    input [3:0] b,
    output [3:0] sum
);
    always @(*) begin
        sum = a + b;
    end
endmodule
```

### Structural Model

```verilog
// Structural: Builds from half-adders
module adder_structural (
    input [3:0] a,
    input [3:0] b,
    output [3:0] sum
);
    wire [3:0] sum;
    wire c0, c1, c2, c3;

    half_adder ha0 (.a(a[0]), .b(b[0]), .s(sum[0]), .c(c0));
    half_adder ha1 (.a(a[1]), .b(b[1]), .s(sum[1]), .c(c1));
    half_adder ha2 (.a(a[2]), .b(b[2]), .s(sum[2]), .c(c2));
    half_adder ha3 (.a(a[3]), .b(b[3]), .s(sum[3]), .c(c3));

    // Full adder connections
    full_adder fa0 (.a(a[0]), .b(b[0]), .cin(c0), .s(sum[0]), .cout(c1));
    full_adder fa1 (.a(a[1]), .b(b[1]), .cin(c1), .s(sum[1]), .cout(c2));
    full_adder fa2 (.a(a[2]), .b(b[2]), .cin(c2), .s(sum[2]), .cout(c3));
    full_adder fa3 (.a(a[3]), .b(b[3]), .cin(c3), .s(sum[3]), .cout(1'b0));
endmodule
```

